# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_financial_transactions(transactions, initial_balance):
    balance = initial_balance
    
    for transaction in transactions:
        if 'credit' in transaction:
            balance += transaction['amount']
        elif 'debit' in transaction:
            balance -= transaction['amount']
    
    return balance

# Example usage:
transactions = [
    {'credit': 100},
    {'debit': 50},
    {'credit': 200}
]
initial_balance = 300
final_balance = process_financial_transactions(transactions, initial_balance)
print(f"Final Balance: {final_balance}")